const ALLOWED_USERS = ['6272541552'];
const msg = $input.first().json.message;
if (!msg) return [];  // callback_queries routed elsewhere

const fromId = String(msg.from?.id || '');
if (!ALLOWED_USERS.includes(fromId)) throw new Error('Unauthorized user ' + fromId);
const chatId = msg.chat.id;
const rawText = (msg.text || '').trim();

const TG_SEND = 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage';
async function tgSend(text) {
  try {
    await this.helpers.httpRequest({
      method: 'POST', url: TG_SEND, json: true,
      body: { chat_id: chatId, text, parse_mode: 'Markdown' },
      timeout: 8000,
    });
  } catch (_) { /* ignore */ }
}

function mdEscape(s) {
  // Markdown V1 only needs these: _, *, `, [. Escape each with backslash so Telegram
  // treats user-supplied text as literal and doesn't 400 on unbalanced markers.
  return String(s == null ? '' : s).replace(/([_*`\[])/g, '\\$1');
}

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  if (m === 0) return n; if (n === 0) return m;
  const dp = Array.from({length: m+1}, () => new Array(n+1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) for (let j = 1; j <= n; j++) {
    dp[i][j] = Math.min(dp[i-1][j] + 1, dp[i][j-1] + 1, dp[i-1][j-1] + (a[i-1] === b[j-1] ? 0 : 1));
  }
  return dp[m][n];
}
function fuzzyMatchCommand(token) {
  // Tightened to 2 (was 3) so generic topic words like 'claude' or
  // 'chrome' don't accidentally fuzzy-match 'clear' or 'stop'.
  const CMDS = ['reel','help','commands','cancel','stop','clear','reset','status'];
  let best = null, bestDist = 3;  // strict: only distance < 3 wins
  for (const c of CMDS) {
    const d = levenshtein(token, c);
    if (d < bestDist) { best = c; bestDist = d; }
  }
  // Extra guard: fuzzy match only accepted when the user typed a slash.
  // Without the slash, we treat the text as a topic (safer default).
  return best;
}

// ---------- Tokenize ----------
const hasSlashPrefix = /^\s*\/+/.test(rawText);
let stripped = rawText.replace(/^\s*\/+/, '').trim();
let bypassIdempotency = false;
if (/^reel!/i.test(stripped)) {
  bypassIdempotency = true;
  stripped = stripped.replace(/^reel!\s*/i, 'reel ');
}
const parts = stripped.split(/\s+/);
const first = (parts[0] || '').toLowerCase();
const rest = parts.slice(1).join(' ').trim();
const KNOWN = new Set(['reel','help','commands','cancel','stop','clear','reset','status']);

// Intent resolution:
//  - Empty input        -> /help
//  - Exact known token  -> that command, topic = rest
//  - Slash + typo (fuzzy match distance<=2) -> guessed command, topic = rest
//  - Everything else    -> /reel, topic = FULL stripped text (prior bug: used
//    only `rest` which dropped the first token when it was the topic itself).
let cmd;
let topic;
if (!first) {
  cmd = 'help';
} else if (KNOWN.has(first)) {
  cmd = first;
  topic = rest;
} else {
  const guess = hasSlashPrefix ? fuzzyMatchCommand(first) : null;
  if (guess) {
    cmd = guess;
    topic = rest;
  } else {
    cmd = 'reel';
    topic = stripped;  // full text, not just rest
  }
}

if (cmd === 'help' || cmd === 'commands') {
  await tgSend(
    '*AI Reel Generator, commands*\n\n' +
    '`/reel <topic>`, research + 3 candidate cards + render an approved reel\n' +
    '`/reel! <topic>`, force regenerate, skip duplicate check\n' +
    '`/status`, heartbeat + last-run summary\n' +
    '`/cancel`, mark the most recent pending job as cancelled (render will refuse to run)\n' +
    '`/clear`, delete all stored candidate jobs\n' +
    '`/help`, this message\n\n' +
    'Typos on slash-commands tolerated. A plain topic with no `/reel` prefix is treated as `/reel <topic>`.'
  );
  return [];
}
if (cmd === 'cancel' || cmd === 'stop') {
  let cancelled = 0;
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST', url: 'http://host.docker.internal:5555/jobs/cancel',
      json: true, body: { user_id: fromId }, timeout: 8000,
    });
    cancelled = resp?.cancelled_count || 0;
  } catch (e) {
    await tgSend('Could not reach the cancel endpoint: ' + (e.message||e));
    return [];
  }
  await tgSend(cancelled > 0
    ? 'Cancelled ' + cancelled + ' pending job(s). Any Approve tap on those cards will be rejected.'
    : 'No pending jobs to cancel.');
  return [];
}
if (cmd === 'clear' || cmd === 'reset') {
  let removed = 0;
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST', url: 'http://host.docker.internal:5555/jobs/clear',
      json: true, body: { user_id: fromId }, timeout: 10000,
    });
    removed = resp?.removed_count || 0;
  } catch (e) {
    await tgSend('Could not reach the clear endpoint: ' + (e.message||e));
    return [];
  }
  await tgSend('Cleared ' + removed + ' stored job(s). Fresh start.');
  return [];
}
if (cmd === 'status') {
  let stats = null;
  try {
    stats = await this.helpers.httpRequest({
      method: 'GET', url: 'http://host.docker.internal:5555/jobs/stats',
      json: true, timeout: 5000,
    });
  } catch (e) { /* ignore */ }
  const lines = [ '*AI Reel Generator, status*' ];
  if (stats) {
    lines.push('Jobs on disk: ' + (stats.jobs_count ?? '?'));
    lines.push('Rendered MP4s: ' + (stats.mp4_count ?? '?'));
    if (stats.last_job) lines.push('Most recent job: ' + stats.last_job);
  } else {
    lines.push('(render-bridge unreachable)');
  }
  await tgSend(lines.join('\n'));
  return [];
}

// /reel <topic>
if (!topic) topic = 'recent AI updates';
const normalizedTopic = topic.toLowerCase().trim();

const BRAND_KEYWORDS = [
  { source: 'anthropic', keys: ['anthropic','claude','sonnet','opus','haiku'] },
  { source: 'openai', keys: ['openai','gpt','chatgpt','codex','sora','dall-e','dalle'] },
  { source: 'google-ai', keys: ['google','bard','notebooklm','chrome'] },
  { source: 'deepmind', keys: ['gemini','deepmind','genie','imagen','veo'] },
  { source: 'meta-ai', keys: ['meta','llama','fair','emu'] },
  { source: 'huggingface', keys: ['huggingface','hugging face','transformers','smol','smolvla'] },
];
let preferredSource = null;
for (const b of BRAND_KEYWORDS) {
  if (b.keys.some(k => normalizedTopic.includes(k))) { preferredSource = b.source; break; }
}

if (!bypassIdempotency) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'http://host.docker.internal:5555/jobs/recent?topic=' + encodeURIComponent(normalizedTopic) + '&window_sec=3600',
      json: true, timeout: 5000,
    });
    if (resp && resp.match && resp.match.job_id) {
      const ageMin = Math.floor(resp.match.age_sec / 60);
      await tgSend(
        'I already pulled cards for *' + mdEscape(topic) + '* ' + ageMin + ' min ago (job `' + resp.match.job_id + '`).\n\n' +
        'To regenerate anyway, reply:\n`/reel! ' + mdEscape(topic) + '`\n\n' +
        'Or tap Approve on the existing cards above.'
      );
      return [];
    }
  } catch (_) { /* proceed without idempotency if bridge is unreachable */ }
}

const jobId = 'reel-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
return [{
  json: {
    job_id: jobId, topic, chat_id: chatId, message_id: msg.message_id, from_id: fromId,
    duration_sec: 90, publish: false, preferred_source: preferredSource,
    ts: new Date().toISOString(),
  }
}];

// Parallel fetch of AI-news RSS feeds.
// Order feeds so the preferred source (from Parse Command + Authorize) goes
// first, Claude Rank weighs feed order lightly, and stable ordering helps
// the zero-match fallback DM be deterministic.
const ALL_FEEDS = [
  { source: 'anthropic', url: 'https://news.google.com/rss/search?q=anthropic+OR+claude&hl=en-US&gl=US&ceid=US:en' },
  { source: 'openai', url: 'https://openai.com/news/rss.xml' },
  { source: 'google-ai', url: 'https://blog.google/technology/ai/rss/' },
  { source: 'deepmind', url: 'https://deepmind.google/blog/rss.xml' },
  { source: 'meta-ai', url: 'https://news.google.com/rss/search?q=%22Meta+AI%22+OR+llama&hl=en-US&gl=US&ceid=US:en' },
  { source: 'huggingface', url: 'https://huggingface.co/blog/feed.xml' }
];

const ctx = $('Parse Command + Authorize').first().json;
const preferred = ctx.preferred_source;
const FEEDS = preferred
  ? [
      ...ALL_FEEDS.filter(f => f.source === preferred),
      ...ALL_FEEDS.filter(f => f.source !== preferred),
    ]
  : ALL_FEEDS;

const results = [];
const feedErrors = [];
const sourceCounts = {};

await Promise.all(FEEDS.map(async (feed) => {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: feed.url,
      timeout: 10000,
      headers: { 'User-Agent': 'Mozilla/5.0 AI-Reel-Generator/1.0' }
    });
    const xml = typeof res === 'string' ? res : String(res);
    const itemBlocks = xml.match(/<item[\s\S]*?<\/item>/g) || [];
    let added = 0;
    for (const block of itemBlocks.slice(0, 15)) {
      const t = (block.match(/<title[^>]*>([\s\S]*?)<\/title>/) || [])[1] || '';
      const l = (block.match(/<link[^>]*>([\s\S]*?)<\/link>/) || [])[1] || '';
      const d = (block.match(/<description[^>]*>([\s\S]*?)<\/description>/) || [])[1] || '';
      const p = (block.match(/<pubDate[^>]*>([\s\S]*?)<\/pubDate>/) || [])[1] || '';
      const cleanTitle = t.replace(/<!\[CDATA\[/g, '').replace(/\]\]>/g, '').trim();
      const cleanLink = l.replace(/<!\[CDATA\[/g, '').replace(/\]\]>/g, '').trim();
      const cleanDesc = d.replace(/<!\[CDATA\[/g, '').replace(/\]\]>/g, '').replace(/<[^>]+>/g, '').trim().slice(0, 400);
      if (cleanTitle && cleanLink) {
        results.push({ source: feed.source, title: cleanTitle, link: cleanLink, description: cleanDesc, pubDate: p });
        added += 1;
      }
    }
    sourceCounts[feed.source] = added;
  } catch (err) {
    feedErrors.push({ source: feed.source, error: String(err && err.message ? err.message : err).slice(0, 120) });
    sourceCounts[feed.source] = 0;
  }
}));

return results.map(r => ({ json: { ...ctx, ...r, _feedErrors: feedErrors, _sourceCounts: sourceCounts } }));

// Filter to last 7 days, dedupe by title, drop junk
const items = $input.all();
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

const seen = new Set();
const out = [];

for (const item of items) {
  const d = item.json;
  let dateObj;
  try { dateObj = new Date(d.pubDate); } catch (e) { dateObj = new Date(); }
  if (isNaN(dateObj.getTime())) dateObj = new Date();
  if (d.pubDate && dateObj < sevenDaysAgo) continue;

  const titleKey = (d.title || '').toLowerCase().trim().replace(/[^a-z0-9]/g, '');
  if (!titleKey || titleKey.length < 10) continue;
  if (seen.has(titleKey)) continue;
  seen.add(titleKey);

  out.push({
    json: {
      job_id: d.job_id,
      topic: d.topic,
      chat_id: d.chat_id,
      source: d.source,
      title: d.title,
      link: d.link,
      description: d.description,
      pubDate: dateObj.toISOString()
    }
  });
}

if (out.length === 0) {
  throw new Error('No fresh stories after normalize. RSS feeds may all be stale or unreachable.');
}

return out;

const items = $input.all();
const ctx = items[0].json;
const topic = ctx.topic || 'recent AI updates';
const preferred = ctx.preferred_source;
const stories = items.map((it, i) => `[${i}] (${it.json.source}) ${it.json.title}\n    ${it.json.description}\n    ${it.json.link}`).join('\n\n');

const preferredClause = preferred
  ? `\n\nPREFERENCE: when multiple stories match the topic, STRONGLY prefer stories whose source is "${preferred}", that is the official RSS for this topic.`
  : '';

const system = `You are a sharp AI news editor ranking stories for a 90-second vertical Reel.

CRITICAL RULES:
1. The user specifies a TOPIC FOCUS. Your PRIMARY job is to pick stories that are clearly relevant to that topic.
2. If the topic names a specific company (Anthropic, OpenAI, Google, Meta, DeepMind, Hugging Face), a specific product (Claude, GPT, Gemini, Llama), a specific model version, or a theme (safety, coding, vision, audio), only pick stories that directly match.
3. If fewer than 3 stories match, return only those (0, 1, or 2 indices) rather than padding with off-topic stories.
4. Within matching stories, prefer ones with concrete numbers (benchmarks, pricing, versions), high recency, and reject vague announcements.
5. Return ONLY a JSON array of integer indices, ordered best-first. No prose, no explanation.${preferredClause}`;

const user = `TOPIC FOCUS: "${topic}"

Available stories:
${stories}

Return a JSON array of 0 to 3 story indices matching the topic, best first. Examples: [4, 1, 7] or [2] or [].`;

return [{ json: { ...ctx, _stories: items.map(it => it.json), system, user } }];

