const items = $input.all();
const claudeResponse = items[0].json;
const priorCtx = $('Build Filter Prompt').first().json;
const stories = priorCtx._stories;
// Pull the per-source counts + feed errors captured in Fetch All RSS Feeds.
const sourceCounts = (stories[0] && stories[0]._sourceCounts) || {};
const feedErrors = (stories[0] && stories[0]._feedErrors) || [];

const text = (claudeResponse && claudeResponse.content && claudeResponse.content[0] && claudeResponse.content[0].text) || '[]';
const match = text.match(/\[[\s\S]*?\]/);
if (!match) {
  throw new Error('Claude rank did not return a JSON array. Got: ' + text.slice(0, 200));
}
let indices;
try { indices = JSON.parse(match[0]); } catch (e) { throw new Error('Bad JSON from Claude rank: ' + match[0]); }

const seen = new Set();
const picked = [];
for (const i of indices) {
  const idx = Number(i);
  if (!Number.isInteger(idx) || idx < 0 || idx >= stories.length) continue;
  if (seen.has(idx)) continue;
  seen.add(idx);
  picked.push(stories[idx]);
  if (picked.length >= 3) break;
}

if (picked.length === 0) {
  const topic = priorCtx.topic || 'your topic';
  const okLine = Object.entries(sourceCounts)
    .filter(([s,n]) => n > 0)
    .map(([s,n]) => s + ' (' + n + ')')
    .join(', ') || '(none)';
  const failLine = feedErrors.length > 0
    ? feedErrors.map(e => e.source + ' [' + e.error + ']').join(', ')
    : 'none';
  const msg = [
    'No stories matched "' + topic + '" in the last 7 days.',
    '',
    'Feeds returning stories: ' + okLine,
    'Feeds that failed: ' + failLine,
    '',
    'Try a broader topic:',
    '  /reel recent AI updates',
    '  /reel openai',
    '  /reel anthropic',
    '  /reel google deepmind',
    '',
    'Or rerun in a few hours as feeds refresh.',
  ].join('\n');
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
      json: true,
      body: { chat_id: priorCtx.chat_id, text: msg },
      timeout: 10000,
    });
  } catch (e) { /* ignore, empty cards list is its own signal */ }
  return [];
}

return picked.map((s, idx) => ({
  json: {
    source: s.source, title: s.title, link: s.link, description: s.description, pubDate: s.pubDate,
    job_id: priorCtx.job_id,
    topic: priorCtx.topic,
    chat_id: priorCtx.chat_id,
    candidate_index: idx,
    candidate_label: ['A', 'B', 'C'][idx]
  }
}));

// Per candidate: classify archetype, then build a topic-specific scene kit
// prompt for Claude Sonnet. Variety additions (2026-04-23):
//   - Seeded PRNG so each reel has a reproducible but unique composition
//   - Archetype-specific opener pools (not always VersionReveal)
//   - Forced wildcard scene from the long tail (not always the obvious picks)
//   - Hard no-duplicate-scene-type constraint in prompt
const s = $json;

// -------- 1. Archetype classification (deterministic keyword match) --------
const topicText = (s.topic || '').toLowerCase();
const contextText = ((s.title || '') + ' ' + (s.description || '')).toLowerCase();

const RULES = [
  { k: 'technical_deep_dive',  res: [/\bbenchmark/i, /\bapi\b/i, /\bsdk\b/i, /\bcli\b/i, /\bpython\b/i, /\bgithub\b/i, /pull[- ]request/i, /\blatency\b/i, /\binference\b/i, /throughput/i, /swe-bench/i, /mmlu/i, /humaneval/i, /codex/i, /\bcode\b/i, /\btoken/i] },
  { k: 'controversy_policy',   res: [/lawsuit/i, /regulat/i, /\bban\b/i, /safety/i, /\brisk\b/i, /\bdanger/i, /\bbias\b/i, /hallucin/i, /jailbreak/i, /\bpolicy\b/i, /\bcourt\b/i, /\bsued\b/i, /\bfine\b/i, /violat/i, /misuse/i, /\bunsafe\b/i] },
  { k: 'business_partnership', res: [/partner/i, /\bdeal\b/i, /acqui/i, /invest/i, /\bfund/i, /enterprise/i, /deploy/i, /rollout/i, /\brevenue/i, /\$\s?\d+/i, /\d+[mbk]\s?(dollar|usd|valuation)/i, /accenture/i, /\bhyatt\b/i] },
  { k: 'industry_stats',       res: [/million users/i, /\bbillion\b/i, /market share/i, /\badoption\b/i, /penetrat/i, /quarter/i, /\bannual\b/i, /year-over-year/i, /\byoy\b/i, /growth rate/i, /\d+%\s*(growth|increase)/i] },
  { k: 'story_impact',         res: [/case study/i, /\bjourney\b/i, /\btransform/i, /accelerat/i, /employee/i, /\bfor (our|their) team\b/i] },
  { k: 'feature_capability',   res: [/\bnow supports?\b/i, /\bcan now\b/i, /\badds?\b/i, /\brolling out\b/i, /\bavailable\b/i, /\bsupports\b/i] },
  { k: 'launch_announcement',  res: [/launch/i, /\brelease/i, /\bdrop/i, /announc/i, /introduc/i, /\bunveil/i, /\bpresent/i, /\breveal/i] },
];
function scoreFor(regexes, topic, context) {
  let s2 = 0;
  for (const re of regexes) {
    if (re.test(topic)) s2 += 3;
    if (re.test(context)) s2 += 1;
  }
  return s2;
}
const scores = RULES.map(r => ({ k: r.k, s: scoreFor(r.res, topicText, contextText) }));
scores.sort((a, b) => b.s - a.s);
let archetype = scores[0].s > 0 ? scores[0].k : 'launch_announcement';
if (scores.length > 1 && scores[0].s === scores[1].s && scores[0].s > 0) {
  const scoreTopicOnly = (rule) => rule.res.reduce((n, re) => n + (re.test(topicText) ? 1 : 0), 0);
  const topRule = RULES.find(r => r.k === scores[0].k);
  const nextRule = RULES.find(r => r.k === scores[1].k);
  if (scoreTopicOnly(nextRule) > scoreTopicOnly(topRule)) archetype = scores[1].k;
}

// Current date, injected into the prompt so Claude never hallucinates
// release years. Sonnet's knowledge cutoff is late 2025, so without this
// it defaults to '2025' for 2026-era launches.
const TODAY = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
const TODAY_YEAR = new Date().getFullYear();
const STORY_PUB_DATE = s.pubDate ? String(s.pubDate).slice(0, 10) : null;

// -------- 2. Archetype -> scene kit + guidance --------
const KITS = {
  launch_announcement: {
    vibe: 'celebratory launch, big version number, announcement social, one hero image, key capabilities',
    prefer: ['VersionReveal','MockTweetCard','BrollClip','BadgeOverlay','CommandPills','SkillLabel','PricingReveal','IconGrid','CTAOutro'],
    avoid:  ['MockTerminal','MockEditor','SeverityCards'],
  },
  technical_deep_dive: {
    vibe: 'numbers-first, benchmarks, bar charts, code demos, developer-oriented visuals',
    prefer: ['VersionReveal','ComparisonCards','ProgressBars','MockTerminal','MockEditor','CodeInline','BadgeOverlay','StatBlock','VsTimeline','CTAOutro'],
    avoid:  ['MockTweetCard','MapMoment','IconGrid'],
  },
  feature_capability: {
    vibe: 'walk through features one by one, instructional, product-focused',
    prefer: ['VersionReveal','CommandPills','SkillLabel','SkillDone','BrowserReveal','BadgeOverlay','CodeInline','IconGrid','PricingReveal','CTAOutro'],
    avoid:  ['SeverityCards','CounterPain'],
  },
  business_partnership: {
    vibe: 'business + scale, partner imagery, reach numbers, global map',
    prefer: ['VersionReveal','BrollClip','MockTweetCard','BadgeOverlay','CommandPills','MapMoment','DoubleStatHero','IconGrid','StatBlock','CTAOutro'],
    avoid:  ['MockTerminal','MockEditor','ProgressBars','SeverityCards','CodeInline'],
  },
  controversy_policy: {
    vibe: 'provocative, severity markers, provocative questions, stark stats, pulled quotes',
    prefer: ['VersionReveal','SeverityCards','CounterPain','BadgeOverlay','HeroQuestion','QuoteCallout','BrollClip','CTAOutro'],
    avoid:  ['CommandPills','MockTweetCard','SkillLabel','PricingReveal','IconGrid'],
  },
  industry_stats: {
    vibe: 'numbers, animated counters, stat blocks, hero stats side by side',
    prefer: ['VersionReveal','BadgeOverlay','CounterPain','ProgressBars','StatBlock','DoubleStatHero','VsTimeline','BrollClip','CTAOutro'],
    avoid:  ['MockTerminal','MockEditor','MockTweetCard','CodeInline'],
  },
  story_impact: {
    vibe: 'human story, hero image, pulled quote, scale stats, source social',
    prefer: ['VersionReveal','BrollClip','QuoteCallout','BadgeOverlay','MockTweetCard','CommandPills','DoubleStatHero','MapMoment','CTAOutro'],
    avoid:  ['MockTerminal','MockEditor','ComparisonCards','CodeInline'],
  },
};
const kit = KITS[archetype];

// -------- 3. Brand hint --------
const SRC_TO_BRAND = {
  openai: 'openai', anthropic: 'anthropic', 'google-ai': 'google',
  deepmind: 'gemini', 'meta-ai': 'meta', huggingface: 'huggingface',
};
const brandHint = SRC_TO_BRAND[s.source] || 'generic';

// -------- 4. Seeded PRNG for reproducible variety --------
function fnv1aHash(str) {
  let h = 2166136261 >>> 0;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619) >>> 0;
  }
  return h >>> 0;
}
function mulberry32(seed) {
  let a = seed >>> 0;
  return function() {
    a = (a + 0x6D2B79F5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
// Mix Date.now + Math.random into the seed so close-in-time candidates
// don't cluster on the same opener/wildcard pick.
const rngSeed = (fnv1aHash((s.job_id || '') + ':' + (s.candidate_index ?? 0)) ^ ((Date.now() & 0xffffffff) >>> 0) ^ Math.floor(Math.random() * 0xffffffff)) >>> 0;
const rng = mulberry32(rngSeed);
// Burn a few cycles so Mulberry32's first outputs don't correlate with seed proximity.
for (let _w = 0; _w < 8; _w++) rng();
function shuffle(arr) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
function pickOne(arr) { return arr[Math.floor(rng() * arr.length)]; }

// -------- 5. Variety picks, opener rotation + wildcard injection --------
// Per-archetype opener pool. Each archetype has 3-4 viable openers so no
// single scene dominates the first beat across reels.
const OPENER_POOLS = {
  launch_announcement: ['VersionReveal', 'DoubleStatHero', 'QuoteCallout', 'BrollClip'],
  technical_deep_dive: ['VersionReveal', 'HeroQuestion', 'CounterPain', 'CodeInline'],
  feature_capability: ['VersionReveal', 'HeroQuestion', 'BrowserReveal', 'CommandPills'],
  business_partnership: ['VersionReveal', 'DoubleStatHero', 'QuoteCallout', 'MapMoment'],
  controversy_policy: ['HeroQuestion', 'SeverityCards', 'QuoteCallout', 'CounterPain'],
  industry_stats: ['DoubleStatHero', 'CounterPain', 'HeroQuestion', 'StatBlock'],
  story_impact: ['QuoteCallout', 'BrollClip', 'HeroQuestion', 'DoubleStatHero'],
};

// Underused long-tail scenes. One is forced into every reel.
const WILDCARD_POOL = ['QuoteCallout', 'MapMoment', 'DoubleStatHero', 'StatBlock', 'VsTimeline', 'BrowserReveal', 'CodeInline', 'HeroQuestion'];

const openerPool = (OPENER_POOLS[archetype] || OPENER_POOLS.launch_announcement)
  .filter(sc => !kit.avoid.includes(sc));
const forcedOpener = openerPool.length ? pickOne(shuffle(openerPool)) : 'VersionReveal';

const wildcardCandidates = WILDCARD_POOL.filter(
  sc => !kit.avoid.includes(sc) && sc !== forcedOpener
);
const forcedWildcard = wildcardCandidates.length ? pickOne(shuffle(wildcardCandidates)) : null;

// Sample 5 middle scenes from the archetype prefer list, excluding opener + wildcard + CTAOutro
const middlePool = kit.prefer.filter(
  sc => sc !== forcedOpener && sc !== forcedWildcard && sc !== 'CTAOutro'
);
const sampledMiddle = shuffle(middlePool).slice(0, 5);

// The final kit for this reel: opener + 5 middle + (wildcard if not already in middle) + CTAOutro
const reelKit = [forcedOpener, ...sampledMiddle];
if (forcedWildcard && !reelKit.includes(forcedWildcard)) reelKit.push(forcedWildcard);
reelKit.push('CTAOutro');

// -------- 6. Variety seed for Claude (soft nudge for generation diversity) --------
const seed = String(Date.now()).slice(-3) + '-' + (s.candidate_index ?? 0) + '-r' + (rngSeed % 1000);

// -------- 7. Prompt --------
const SCENE_CATALOG = `
SCENE CATALOG (23 usable scenes, you MUST pick beats from this list):

CORE SHORTS SCENES:
VersionReveal     { label: UPPER, version: 1 word/number, subhead?: str }, opening big reveal
MockTweetCard     { tweet: { handle, display, verified, timestamp, body, engagement: {replies,retweets,likes,views} } }, X/Twitter card
CommandPills      { headline, pills: [{text, accent}] (exactly 3) }, 3-capability grid
BadgeOverlay      { headline, subhead, badge: {text, accent} }, one big stat
MockTerminal      { title, prompt, status, logLines: [{role, text}] (4-6) }, CLI demo (ONLY for code/tech topics)
MockEditor        { filename, lines: [{text, color, check?}] (4-8) }, code diff view
SkillLabel        { label: "ONE"|"TWO"|"THREE", command: 1-2 words }, step marker
SkillDone         { done, tease }, transition between features
ComparisonCards   { headline, comparison: { left: {title, price, features: [3-5 strings], accent}, right: {title, price, features: [3-5 strings], accent}, winner: "left"|"right", winnerLabel?: str } }, vs competitor
BrowserReveal     { url, title, subhead }, web UI reveal
CounterPain       { headline, counter: {label, from, to, durationSec} }, animated before/after number
ProgressBars      { headline, bars: [{label, accent, targetPct}] (3-5) }, benchmark-style
SeverityCards     { headline, cards: [{severity: "HIGH"|"MED"|"LOW", confidence, title, path}] (3-5) }, risk markers
BrollClip         { title, sourceBadge }, framed article hero image (use AT MOST ONCE)
CTAOutro          { outroStyle: "follow", label, headline, subhead?, cta }, closing beat (ALWAYS the last beat)

TIER-1 NATIVE ADDITIONS:
QuoteCallout      { quote: str (5-15 words), attribution?: str, kicker?: str }, large pull quote, Playfair font
StatBlock         { headline?, stats: [{label, value}] (2-4 tiles) }, 2x2 stat grid
MapMoment         { headline, stat?: str, pins?: [str] (4-8 country names) }, abstract global reach
PricingReveal     { tier?: str, headline?, price: str, unit: str, features: [str] (3-5) }, pricing announcement
VsTimeline        { headline?, markers: [{label, date, highlight?: bool}] (3-5) }, horizontal timeline
IconGrid          { headline, items: [str] (4-8), subhead? }, tool/company tile grid
DoubleStatHero    { headline?, leftStat: {label, value}, rightStat: {label, value}, separator?: str }, two hero stats stacked
CodeInline        { headline?, code: str | [str] (1-3 lines), caption?: str, language?: "bash"|"python"|"js"|"ts"|"sh" }

V7 RESCUED:
HeroQuestion      { headline: str (provocative question, 1 sentence) }, full-bleed question frame

NOTE: do NOT use SplitFactCard, TestimonialCards, CommunityQuoteGrid, TabSelectorPillars, TimelineConnector, UrlRevealCard, SectionDividerCard, BigStatStack, BrandOutroBumper.
`;

const archetypeBlock = `
TOPIC ARCHETYPE: ${archetype}
VIBE: ${kit.vibe}
BRAND: ${brandHint}

SCENE LINEUP FOR THIS SPECIFIC REEL (seed ${seed}):
  REQUIRED OPENER (first beat): ${forcedOpener}
  REQUIRED WILDCARD (must appear somewhere in the middle beats): ${forcedWildcard || '(none)'}
  MIDDLE POOL (draw 4-6 beats from here): ${sampledMiddle.join(', ')}
  REQUIRED CLOSER (last beat): CTAOutro

AVOID for this archetype (wrong vibe unless story demands): ${kit.avoid.join(', ')}

RULES (hard constraints, violations will cause rejection):
  - First beat scene MUST be ${forcedOpener}.
  - Last beat scene MUST be CTAOutro.
  - Somewhere in the middle beats, use ${forcedWildcard || '(no wildcard for this reel)'} at least once.
  - NEVER use the same scene type twice in one reel. Every beat's "scene" value must be unique.
  - Draw middle beats from the MIDDLE POOL. Do not introduce scenes from the AVOID list unless the story explicitly requires it (rare).
  - BrollClip at most once in the whole reel (imagery is only injected once).
`;

const user = `STORY
Source: ${s.source}
Job ID: ${s.job_id}
Candidate: ${s.candidate_label}
Title: ${s.title}
Summary: ${s.description}
Published: ${STORY_PUB_DATE || 'unknown'}
Link: ${s.link}
Today: ${TODAY} (year ${TODAY_YEAR}, use this for any 'released' / 'announced' year references unless the story explicitly says otherwise).

${archetypeBlock}

${SCENE_CATALOG}

TASK:
Write a beat-by-beat script for a 75-90 second vertical Reel.
- 7 to 9 beats.
- Follow the SCENE LINEUP constraints above exactly (required opener, required wildcard, required closer, no duplicates).
- Narration text is what the voice says aloud (1-3 sentences per beat, factual, specific numbers where you have them).
- Hook beat (first) must grab attention in the first 3 seconds.
- Last beat: CTAOutro with cta "Follow for daily AI updates".
- Return ONLY the JSON object matching this shape (no prose, no markdown):

{
  "id": "${s.job_id}",
  "title": "<2-5 word reel headline>",
  "language": "english",
  "voice": "nikunj",
  "brand": "${brandHint}",
  "channel": "reel-generator",
  "format": "short",
  "targetDurationSec": 75-95,
  "archetype": "${archetype}",
  "beats": [
    { "id": "b1", "intent": "<short_snake_case>", "text": "<narration>", "scene": "<SceneName>", "props": { "brand": "${brandHint}", "accent": "<palette-key>", ...scene-specific fields... }, "sfxHints": [0-3 from: whoosh_short whoosh_long slide_in ui_blip ui_chime badge_ping success_ding success_fanfare mech_click ui_tick progress_complete] }
  ]
}

Accent palette keys (strict): coral, cyan, red, green, yellow, orange, purple, pink, blue, white, muted.
`;

const system = `You turn a single AI-news story into a beat-by-beat Remotion script for a 75-90 second vertical Reel. You follow a per-reel scene lineup (specified in the user message) which defines the required opener, closer, and wildcard scene so each reel feels topically distinct. No two beats use the same scene type. Output ONLY valid JSON matching the target shape, no prose, no markdown.\n\nDATE GROUNDING: Today is ${TODAY} (year ${TODAY_YEAR}). The source story was published on ${STORY_PUB_DATE || 'unknown date'}. When referencing when something was released or launched, use the story's pubDate year, NOT your training data's default. If a model or product is described in the story as 'just released' or 'announced today', its year is ${STORY_PUB_DATE ? STORY_PUB_DATE.slice(0,4) : TODAY_YEAR}. Never write '2025' unless the story explicitly says 2025.`;

return { json: { ...s, archetype, _variety: { opener: forcedOpener, wildcard: forcedWildcard, middle: sampledMiddle, seed: rngSeed }, _system: system, _user: user } };

