parameters.jsCode:
const claude = $json;
const text = (claude && claude.content && claude.content[0] && claude.content[0].text) || '';
const openIdx = text.indexOf('{');
const closeIdx = text.lastIndexOf('}');
if (openIdx < 0 || closeIdx <= openIdx) {
  throw new Error('Claude scene plan returned no JSON object. Got: ' + text.slice(0, 200));
}
const raw = text.slice(openIdx, closeIdx + 1);
let spec;
try { spec = JSON.parse(raw); } catch (e) {
  throw new Error('Bad JSON from scene plan: ' + raw.slice(0, 200));
}

if (!spec.beats || !Array.isArray(spec.beats) || spec.beats.length === 0) {
  throw new Error('Scene plan has no beats: ' + raw.slice(0, 200));
}

// Duplicate-scene rejection: if Claude ignored the "no duplicates" rule, rewrite
// offending beats by swapping to the first unused alternate from the archetype kit.
// This is a soft rescue rather than a hard failure, we prefer one rescued beat
// over a failed render.
const seenScenes = new Set();
const REWRITE_FALLBACKS = ['BadgeOverlay', 'CommandPills', 'QuoteCallout', 'StatBlock', 'IconGrid', 'BrollClip', 'DoubleStatHero', 'MapMoment'];
let rewriteCount = 0;
for (const b of spec.beats) {
  const sc = b.scene;
  if (!sc) continue;
  if (seenScenes.has(sc)) {
    // find a fallback not already used
    const fb = REWRITE_FALLBACKS.find(f => !seenScenes.has(f));
    if (fb) {
      b.scene = fb;
      b._rewritten_from = sc;
      rewriteCount++;
    }
  }
  seenScenes.add(b.scene);
}
if (rewriteCount > 0) spec._rewrites = rewriteCount;

spec.id = spec.id || ('reel-' + Date.now());
spec.language = spec.language || 'english';
spec.voice = spec.voice || 'nikunj';
spec.channel = spec.channel || 'reel-generator';
spec.format = 'short';
if (!spec.targetDurationSec) spec.targetDurationSec = 85;

const seen = new Set();
for (let i = 0; i < spec.beats.length; i++) {
  const b = spec.beats[i];
  if (!b.id || seen.has(b.id)) b.id = 'b' + (i + 1);
  seen.add(b.id);
  b.sfxHints = Array.isArray(b.sfxHints) ? b.sfxHints : [];
  b.props = b.props || {};
}

const storyCtx = $('Build Scene Plan Prompt').item.json;
return {
  json: {
    job_id: storyCtx.job_id,
    topic: storyCtx.topic,
    chat_id: storyCtx.chat_id,
    candidate_index: storyCtx.candidate_index,
    candidate_label: storyCtx.candidate_label,
    source: storyCtx.source,
    title: storyCtx.title,
    link: storyCtx.link,
    description: storyCtx.description,
    content_json: spec
  }
};

const items = $input.all();
if (items.length === 0) throw new Error('No scene plans produced');
const rootCtx = $('Parse Command + Authorize').first().json;
const chatId = rootCtx.chat_id;
const jobId = rootCtx.job_id;

if (!chatId) throw new Error('chat_id missing');
if (!jobId) throw new Error('job_id missing');

const cards = items.map(it => {
  const d = it.json;
  const cj = d.content_json || {};
  const beatSummary = (cj.beats || []).slice(0, 5).map((b, i) =>
    `${i + 1}. ${b.scene}: ${(b.text || '').slice(0, 80)}${(b.text || '').length > 80 ? '...' : ''}`
  ).join('\n');
  const totalBeats = (cj.beats || []).length;
  const extraBeats = totalBeats > 5 ? `\n...and ${totalBeats - 5} more` : '';

  const text = [
    `*Candidate ${d.candidate_label}*  (${d.source})  |  brand: ${cj.brand || '?'}`,
    ``,
    `*${cj.title || d.title}*`,
    ``,
    beatSummary + extraBeats,
    ``,
    `Beats: ${totalBeats}   |   Target: ~${cj.targetDurationSec || 85}s`,
    `[source](${d.link})`
  ].join('\n');

  return {
    json: {
      chat_id: chatId,
      text,
      parse_mode: 'Markdown',
      reply_markup: {
        inline_keyboard: [[
          { text: `✅ Approve ${d.candidate_label}`, callback_data: `approve:${jobId}:${d.candidate_index}` },
          { text: '❌ Reject', callback_data: `reject:${jobId}:${d.candidate_index}` }
        ]]
      }
    }
  };
});

return cards;

const plans = $('Parse Scene Plans').all();
if (plans.length === 0) return [];
const ctx = $('Parse Command + Authorize').first().json;
const jobId = plans[0].json.job_id;
const chatId = plans[0].json.chat_id;
const topic = ctx.topic || plans[0].json.topic || '';
const preferredSource = ctx.preferred_source || null;
const payload = {
  created_at: new Date().toISOString(),
  chat_id: chatId,
  from_id: ctx.from_id,
  topic,
  preferred_source: preferredSource,
  status: 'pending',
  candidates: plans.map(p => ({
    index: p.json.candidate_index,
    label: p.json.candidate_label,
    source: p.json.source,
    title: p.json.title,
    link: p.json.link,
    content_json: p.json.content_json,
  })),
};
const json_str = JSON.stringify(payload, null, 2);
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(json_str, 'utf8'),
  jobId + '.json',
  'application/json'
);
return [{
  json: { job_id: jobId, chat_id: chatId, candidates_count: plans.length },
  binary: { data: binaryData },
}];
